INSERT INTO order_item (
    order_id, product_id, sku_id, product_name, product_image, sku_specs,
    origin_price, final_price, price, quantity,
    item_origin_amount, item_final_amount, promotion_type
) VALUES (
    #{orderId}, #{productId}, #{skuId}, #{productName}, #{productImage}, #{skuSpecs},
    #{originPrice}, #{finalPrice}, #{price}, #{quantity},
    #{itemOriginAmount}, #{itemFinalAmount}, #{promotionType}
)

INSERT INTO order_status_log (
    order_id, from_status, to_status, status_text,
    operator_type, operator_id, remark, create_time
) VALUES (
    #{orderId}, #{fromStatus}, #{toStatus}, #{statusText},
    #{operatorType}, #{operatorId}, #{remark}, #{createTime}
)

mapper.select:
SELECT 
FROM `order`
WHERE user_id = #{userId} AND COALESCE(user_deleted, 0) = 0

    AND status = #{status}

ORDER BY create_time DESC, id DESC
LIMIT #{offset}, #{pageSize}

mapper.update:
UPDATE sku
SET stock = stock - #{quantity}
WHERE id = #{skuId} AND stock >= #{quantity}

UPDATE sku
SET stock = stock + #{quantity}
WHERE id = #{skuId}

UPDATE `order`
SET status = #{status}, pay_time = #{payTime}, update_time = #{updateTime}
WHERE id = #{orderId} AND status = 0

UPDATE `order`
SET status = #{status}, update_time = #{updateTime}
WHERE id = #{orderId}

UPDATE `order`
SET points_status = #{toStatus}, update_time = NOW()
WHERE id = #{orderId} AND points_status = #{fromStatus}
